messages.content:
CLUSTER:
[
 {
  "riskId": "risk.base-rate-analogy.framework-foreclosure-beachhead",
  "title": "The chosen beachhead buys through global frameworks: half the large-operator cell is not a market for a regional entrant",
  "narrative": "The venture's stated first channel is large operators, and the model gives that cell 40% of PDU spend on the logic 'large operators buy direct'. The corpus shows what 'direct' actually means at that scale: Digital Realty's $373M Schneider framework agreement, Iren's $1.6bn all-in Dell contract, PDU spend embedded as one line inside integrated rack/power/cooling packages. Combined with CR3 ≈ 0.55 among vendors who sell exactly those bundles, the buying event a new entrant needs — a discrete, multi-bidder PDU bake-off at a large operator — is disappearing. The only standalone PDU procurements found in the corpus were small, 1-2 bidder, sometimes explicitly sole-sourced. The beachhead the profile names is the cell most structurally closed to the venture; the model prices it as the biggest open door.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large operators consolidate rack-power purchasing into multi-year global framework agreements and integrated vendor packages rather than discrete PDU line items — the exact procurement pattern documented in the cust.operator-large evidence trail",
    "refs": [
     "ledger:cust.operator-large",
     "digest:cr3-vendors#c1"
    ]
   },
   {
    "step": "propagation",
    "text": "With the #1 vendor alone at 15.8% and a semi-consolidated top set (Schneider, Vertiv, Eaton, ABB, Legrand) selling bundled infrastructure, framework renewal — not open tender — becomes the default buying event; the residual standalone tenders observed were 1-2 bidder or sole-sourced ('No substitutions')",
    "refs": [
     "digest:cr3-vendors#c0",
     "digest:cr3-vendors#c2",
     "ledger:shape.cr3"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 0.40 large-operator share — itself an unsourced internal estimate with no channel-split evidence — overstates the spend a regional entrant can actually contest; roughly half the cell is foreclosed behind frameworks the entrant cannot enter in year 1, and the venture's go-to-market points straight at it",
    "refs": [
     "ledger:cust.operator-large",
     "profile:Product"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "New or renewed multi-year power-infrastructure framework announcements by CE-active large operators",
    "where": "Digital Realty / Equinix / Vantage / NTT press releases and Schneider/Vertiv/Eaton earnings-call order-book commentary",
    "threshold": "≥2 new CE-relevant frameworks announced covering rack power",
    "updates": "increases"
   },
   {
    "signal": "Bidder counts and substitution clauses on standalone rack-PDU tenders",
    "where": "TED (Tenders Electronic Daily) award notices and operator supplier portals",
    "threshold": "Median bidders ≤2 or 'no substitution' language on >half of observed PDU line items",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.execution-window.framework-agreements-foreclose-large-operator-cell",
  "title": "Global framework agreements make the 0.40 large-operator cell mostly non-contestable in the venture's window",
  "narrative": "The model's biggest customer cell — large operators at 0.40 of PDU spend — encodes the assumption 'large operators buy direct, therefore a direct-selling entrant can compete for them.' But the way large operators buy direct is through multi-year global framework agreements and integrated infrastructure packages with incumbents whose customer lists already span every hyperscaler and major colo. A framework doesn't shrink the cell's spend; it forecloses it: the PDU line is decided once, globally, years at a time, and never comes to regional tender. For a pre-launch regional entrant whose profile explicitly targets large operators first, the nominal 0.40 collapses to the sliver of that spend outside framework coverage — while the model's YAM math quietly credits the whole cell as contestable.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Incumbent rack-power vendors hold entrenched direct relationships with the exact buyers in this cell — Vertiv's disclosed major-customer list alone covers Equinix and the global telcos/hyperscalers — and data-center demand is concentrating supplier order books around these accounts",
    "refs": [
     "digest:cust-mix#c12",
     "digest:cust-mix#c0"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.40 value itself is an unsourced internal estimate: no retrieved source substantiates the channel split, and the one hard number cited (30% of one supplier's orders) measures order composition, not buyer-type contestability — so the cell carries no evidence about how much of it ever reaches open competition",
    "refs": [
     "digest:cust-mix#c0",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "model-impact",
    "text": "If framework-covered spend is removed, the large-operator cell available to a new regional entrant in its first 12–24 months is roughly half its nominal size, and the venture's chosen go-to-market points at the most-foreclosed cell first",
    "refs": [
     "ledger:cust.operator-large",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "New multi-year power-infrastructure framework or integrated-rack supply announcements naming CE operators",
    "where": "Schneider/Vertiv/Eaton quarterly earnings calls and press rooms; operator capex-day presentations",
    "threshold": "≥1 new CE-relevant operator signing a global power framework covering rack distribution",
    "updates": "increases"
   },
   {
    "signal": "Standalone rack-PDU lots appearing (or not) in operator tenders, and their bidder counts",
    "where": "TED (EU tender portal) and operator supplier portals for DE/NL colo fit-outs",
    "threshold": "Standalone PDU lots absent, sole-sourced, or drawing ≤2 bidders across two consecutive quarters",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.ledger-self-audit.framework-agreements-hollow-large-operator-cell",
  "title": "Global framework agreements and bundled fit-outs foreclose the 0.40 large-operator cell the whole GTM is aimed at",
  "narrative": "The venture's stated first buyer is large operators, and cust.operator-large carries the biggest single channel weight (0.40) — a needs-source internal estimate with two-decimal precision. The corpus shows what that cell actually looks like from inside procurement: PDU spend at large operators flows through multi-year global framework agreements and integrated rack/power/cooling bundles (Digital Realty–Schneider style frameworks, all-in integrator contracts), not discrete PDU line items a regional entrant can bid. If half the 0.40 is procured this way, the model's most reachable-looking cell is structurally closed in Year 1 — and the conservative 1% obtainableFactor is being applied to a SAM that contains spend no entrant can contest at any price.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large operators consolidate power-equipment purchasing into global frameworks and integrator bundles; Vertiv's own partner material lists hyperscalers, telcos and colo REITs as house accounts under standing agreements",
    "refs": [
     "digest:cust-mix#c12",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.40 share was derived from 'hyperscale+colo ≈ 62% buy direct' — but the only quantitative datapoint behind the channel axis (a supplier's 30%-of-orders figure) measures DC exposure, not buyer-type contestability, and no source quantifies what fraction of 'direct' spend is framework-locked",
    "refs": [
     "digest:cust-mix#c0",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "model-impact",
    "text": "The contestable portion of the large-operator cell is materially below 0.40; SAM built on the full cell overstates reachable spend for the profile's chosen first buyer, and Year-1 pipeline math against it fails silently",
    "refs": [
     "ledger:cust.operator-large",
     "profile:Who is the primary buyer you'll sell through first?",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Structure of large-operator PDU procurement: discrete lots vs bundled fit-out packages",
    "where": "TED (Tenders Electronic Daily) filtered for PDU/rack-power CPV codes in DE/NL/PL; Digital Realty and Equinix supplier-announcement pages",
    "threshold": "<2 standalone, multi-bidder PDU lots from CE large operators over two consecutive quarters",
    "updates": "increases"
   },
   {
    "signal": "New or renewed multi-year power-infrastructure framework agreements between colo REITs/hyperscalers and Schneider/Vertiv/Eaton",
    "where": "Schneider and Vertiv quarterly earnings calls and press rooms; operator capex-call commentary",
    "threshold": "≥2 new CE-relevant frameworks announced in 12 months",
    "updates": "increases"
   },
   {
    "signal": "Approved-vendor-list (AVL) openings at CE colocation operators",
    "where": "Operator supplier-qualification portals (Equinix, NTT, Data4, Atman)",
    "threshold": "Any AVL round explicitly inviting new rack-PDU vendors",
    "updates": "decreases"
   }
  ],
  "judgeTotal": 17
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
